from dataclasses import dataclass


@dataclass
class BudgetProjection:
    current_budget_pct: float       # e.g. 45.0
    avg_monthly_burn_pct: float     # e.g. 12.0 (historical 3-month average)
    planned_feature_launches: int   # each launch historically burns 3%

    def months_to_exhaustion(self) -> float:
        """How many months before budget hits zero without intervention."""
        monthly_net_burn = self.avg_monthly_burn_pct + (self.planned_feature_launches * 3.0)
        if monthly_net_burn <= 0:
            return float("inf")
        return self.current_budget_pct / monthly_net_burn

    def budget_after_quarter(self) -> float:
        """Projected budget balance in 3 months."""
        total_burn = 3 * self.avg_monthly_burn_pct + self.planned_feature_launches * 3.0
        return max(0.0, self.current_budget_pct - total_burn)


proj = BudgetProjection(
    current_budget_pct=45.0,
    avg_monthly_burn_pct=12.0,
    planned_feature_launches=2,
)
print(f"Budget after quarter: {proj.budget_after_quarter():.1f}%")
print(f"Months to exhaustion: {proj.months_to_exhaustion():.1f}")
# Budget after quarter: 3.0%
# Months to exhaustion: 1.5 → reliability investments needed before Q4 launch

# roadmap_status.py — pull GitHub issues labelled 'reliability-roadmap' and print status
import subprocess, json


def get_roadmap_issues(quarter_label: str = "Q3-2026") -> list[dict]:
    result = subprocess.run(
        [
            "gh", "issue", "list",
            "--label", "reliability-roadmap",
            "--label", quarter_label,
            "--json", "number,title,state,assignees,milestone,updatedAt",
            "--limit", "50",
        ],
        capture_output=True,
        text=True,
        check=True,
    )
    return json.loads(result.stdout)


def print_roadmap_status(issues: list[dict]) -> None:
    by_state: dict[str, list] = {"open": [], "closed": []}
    for issue in issues:
        by_state[issue["state"]].append(issue)

    print(f"Reliability Roadmap Status")
    print(f"Open: {len(by_state['open'])} | Done: {len(by_state['closed'])}")
    print()
    for issue in by_state["open"]:
        assignee = issue["assignees"][0]["login"] if issue["assignees"] else "unassigned"
        print(f"  [ ] #{issue['number']} {issue['title']} (@{assignee})")
    for issue in by_state["closed"]:
        assignee = issue["assignees"][0]["login"] if issue["assignees"] else "unassigned"
        print(f"  [x] #{issue['number']} {issue['title']} (@{assignee})")


if __name__ == "__main__":
    issues = get_roadmap_issues("Q3-2026")
    print_roadmap_status(issues)
